	$icons = apply_filters( 'battleplan_icon_map', $icons );

	if ( $type === '' || !isset( $icons[ $type ][0] ) ) {
		return '';
	}

	$createIcon = '<span class="icon '.$type.'"'.$adjust.'>';

	if ( $before !== '' ) $createIcon .= '<div class="icon-txt-before">'.$before.'</div>';

	$createIcon .= '<svg class="icon-svg icon-'.$type.'" viewBox="0 0 512 512" xmlns="http://www.w3.org/2000/svg">'.$icons[$type][0].'</svg>';

	if ( $after !== '' ) $createIcon .= '<div class="icon-txt-after">'.$after.'</div>';

	$createIcon .= '</span>';

	$buildIcon = '<!--no-wpautop-->';
	if ( $link !== '' ) $buildIcon .= '<a href="'.$link.'" class="icon-btn'.$class.'" role="button"'.$target.'>';

	if ( $grid !== '' && $content !== null && $content !== '' ) {
		$buildIcon .= '<div class="icon-card"><div>'.$createIcon.'</div><div>'.$content.'</div></div>';
	} else {
		$buildIcon .= $createIcon;
	}

	if ( $sr !== '' ) $buildIcon .= '<span class="sr-only">'.$sr.'</span>';
	if ( $link !== '' ) $buildIcon .= '<div class="icon-bg"></div></a>';

	$buildIcon .= '<!--/no-wpautop-->';

	return $buildIcon;
